import React, { useEffect, useState, useMemo } from "react";
import { supabase } from "../supabaseClient";
import { 
    Navigation, LogOut, Search, RefreshCcw, 
    MessageCircle, MapPin, Clock, Calendar, 
    CheckCircle, XCircle, Send, Loader2, Car, Phone
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [timeFilter, setTimeFilter] = useState("all"); // all, today, weekly, monthly
    const [statusFilter, setStatusFilter] = useState("all");

    useEffect(() => {
        fetchRides();
        const sub = supabase.channel('realtime-pahel').on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides()).subscribe();
        return () => supabase.removeChannel(sub);
    }, []);

    const fetchRides = async () => {
        const { data } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (data) setRides(data);
        setLoading(false);
    };

    const updateStatus = async (id, status) => {
        await supabase.from('rides').update({ status }).eq('id', id);
        fetchRides();
    };

    const triggerWhatsApp = (num, name) => {
        const clean = num.replace(/\D/g, '');
        window.open(`https://wa.me/91${clean}?text=Hi ${name}, reaching out from PAHEL regarding your ride booking.`, '_blank');
    };

    // --- FIXING FILTERING LOGIC ---
    const filteredRides = useMemo(() => {
        const now = new Date();
        const todayStr = now.toLocaleDateString('en-CA'); // YYYY-MM-DD format based on local time

        return rides.filter(r => {
            // 1. Time Filtering
            let timeMatch = true;
            const rideDate = new Date(r.ride_date);

            if (timeFilter === 'today') {
                timeMatch = r.ride_date === todayStr;
            } else if (timeFilter === 'weekly') {
                const diffTime = Math.abs(now - rideDate);
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
                timeMatch = diffDays <= 7;
            } else if (timeFilter === 'monthly') {
                timeMatch = rideDate.getMonth() === now.getMonth() && rideDate.getFullYear() === now.getFullYear();
            }

            // 2. Status Filtering
            const statusMatch = statusFilter === 'all' || r.status === statusFilter;

            // 3. Search Filtering (Name, Phone, or Vehicle)
            const searchMatch = 
                r.passenger_name?.toLowerCase().includes(search.toLowerCase()) || 
                r.phone_number?.includes(search) ||
                r.vehicle_class?.toLowerCase().includes(search.toLowerCase());

            return timeMatch && statusMatch && searchMatch;
        });
    }, [rides, timeFilter, statusFilter, search]);

    // Stats Logic
    const stats = useMemo(() => {
        const today = new Date().toLocaleDateString('en-CA');
        return {
            total: rides.length,
            pending: rides.filter(r => r.status === 'pending').length,
            today: rides.filter(r => r.ride_date === today).length,
            completedToday: rides.filter(r => r.status === 'completed' && r.ride_date === today).length
        };
    }, [rides]);

    if (loading) return <div style={{display:'flex', height:'100vh', justifyContent:'center', alignItems:'center'}}><Loader2 className="spin" size={40} color="#2563eb" /></div>;

    return (
        <div className="admin-wrapper">
            <header className="header-section">
                <div className="logo-area">
                    <h1>PAHEL Fleet Manager</h1>
                    <p style={{color: 'var(--text-muted)', fontSize: '14px', marginTop: '4px'}}>Welcome back, {session.user.email}</p>
                </div>
                <div style={{display:'flex', gap:'12px'}}>
                    <button className="action-icon" onClick={fetchRides}><RefreshCcw size={18}/></button>
                    <button className="action-icon" style={{background: 'var(--danger)', color:'#fff', border:'none'}} onClick={() => supabase.auth.signOut()}>
                        <LogOut size={18} />
                    </button>
                </div>
            </header>

            <div className="stats-grid">
                <div className="stat-card">
                    <span className="stat-label">Total Volume</span>
                    <span className="stat-value">{stats.total}</span>
                </div>
                <div className="stat-card" style={{borderLeft: '4px solid var(--warning)'}}>
                    <span className="stat-label">Action Required</span>
                    <span className="stat-value" style={{color: 'var(--warning)'}}>{stats.pending}</span>
                </div>
                <div className="stat-card" style={{borderLeft: '4px solid var(--primary)'}}>
                    <span className="stat-label">Rides Today</span>
                    <span className="stat-value" style={{color: 'var(--primary)'}}>{stats.today}</span>
                </div>
                <div className="stat-card" style={{borderLeft: '4px solid var(--success)'}}>
                    <span className="stat-label">Finished Today</span>
                    <span className="stat-value" style={{color: 'var(--success)'}}>{stats.completedToday}</span>
                </div>
            </div>

            <div className="table-container">
                <div className="filter-bar">
                    <div style={{display:'flex', gap:'15px', alignItems:'center'}}>
                        <div style={{position:'relative'}}>
                            <Search size={16} style={{position:'absolute', left:'12px', top:'12px', color:'var(--text-muted)'}} />
                            <input 
                                type="text" 
                                className="search-input" 
                                placeholder="Search passenger, phone or car..." 
                                style={{paddingLeft: '38px'}}
                                onChange={(e) => setSearch(e.target.value)}
                            />
                        </div>
                        <div className="tab-group">
                            {['all', 'today', 'weekly', 'monthly'].map(t => (
                                <button key={t} onClick={() => setTimeFilter(t)} className={`tab-btn ${timeFilter === t ? 'active' : ''}`}>
                                    {t.toUpperCase()}
                                </button>
                            ))}
                        </div>
                    </div>
                    <select className="search-input" style={{width: '160px'}} onChange={(e) => setStatusFilter(e.target.value)}>
                        <option value="all">All Status</option>
                        <option value="pending">Pending</option>
                        <option value="confirmed">Confirmed</option>
                        <option value="completed">Completed</option>
                    </select>
                </div>

                <div style={{overflowX: 'auto'}}>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Passenger</th>
                                <th>Vehicle Type</th>
                                <th>Route</th>
                                <th>Schedule</th>
                                <th>Status</th>
                                <th style={{textAlign: 'right'}}>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredRides.map(r => (
                                <tr key={r.id}>
                                    <td>
                                        <div style={{fontWeight: 700}}>{r.passenger_name}</div>
                                        <div style={{display:'flex', gap: '8px', marginTop: '6px'}}>
                                            <button onClick={() => triggerWhatsApp(r.phone_number, r.passenger_name)} className="wa-link">
                                                <MessageCircle size={12}/> {r.phone_number}
                                            </button>
                                            {r.alt_phone && (
                                                <button onClick={() => triggerWhatsApp(r.alt_phone, r.passenger_name)} className="wa-link alt">
                                                    <Phone size={12}/> {r.alt_phone}
                                                </button>
                                            )}
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{display:'flex', alignItems:'center', gap:'8px', fontWeight:600, color: 'var(--text-muted)'}}>
                                            <Car size={16} /> {r.vehicle_class || 'Standard'}
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{fontSize: '12px', color: 'var(--success)', fontWeight: 600}}>
                                            <MapPin size={10}/> {r.pickup_location}
                                        </div>
                                        <div style={{fontSize: '12px', color: 'var(--danger)', marginTop: '4px'}}>
                                            <MapPin size={10}/> {r.drop_location}
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{fontWeight: 600}}>{r.ride_date}</div>
                                        <div style={{fontSize: '12px', color: 'var(--text-muted)'}}>{r.ride_time}</div>
                                    </td>
                                    <td>
                                        <span className={`status-pill status-${r.status}`}>{r.status}</span>
                                    </td>
                                    <td>
                                        <div style={{display:'flex', gap:'8px', justifyContent: 'flex-end'}}>
                                            <button onClick={() => updateStatus(r.id, 'confirmed')} className="action-icon" title="Confirm"><Send size={16}/></button>
                                            <button onClick={() => updateStatus(r.id, 'completed')} className="action-icon" title="Complete"><CheckCircle size={16} color="var(--success)"/></button>
                                            <button onClick={() => updateStatus(r.id, 'cancelled')} className="action-icon" title="Cancel"><XCircle size={16} color="var(--danger)"/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                    {filteredRides.length === 0 && (
                        <div style={{padding: '40px', textAlign: 'center', color: 'var(--text-muted)'}}>No rides found for this selection.</div>
                    )}
                </div>
            </div>
            <style>{`.spin { animation: rotate 1s linear infinite; } @keyframes rotate { 100% { transform: rotate(360deg); } }`}</style>
        </div>
    );
};

export default Dashboard;
